from typing import Callable

from flask import Flask, Response, jsonify, request

app = Flask(__name__)

TransformFn = Callable[[str], str | int]

OPERATIONS: dict[str, TransformFn] = {
    "uppercase": str.upper,
    "reverse": lambda text: text[::-1],
    "count_words": lambda text: len(text.split()),
}


def error_response(message: str) -> tuple[Response, int]:
    return jsonify({"error": message}), 400


@app.post("/api/transform")
def transform_text() -> tuple[Response, int]:
    """Accept JSON text input and return the requested text transformation."""
    data = request.get_json(silent=True)

    if not isinstance(data, dict):
        return error_response("Request body must be valid JSON.")

    text = data.get("text")
    if not isinstance(text, str):
        return error_response("The 'text' field is required and must be a string.")

    operation = data.get("operation")
    if not isinstance(operation, str) or operation not in OPERATIONS:
        return error_response(
            "The 'operation' field is required and must be one of: "
            "uppercase, reverse, count_words."
        )

    result = OPERATIONS[operation](text)

    return jsonify(
        {
            "result": result,
            "operation": operation,
            "original_length": len(text),
        }
    ), 200


if __name__ == "__main__":
    app.run(debug=True, port=5000)
